// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package hashcodeimport ("bytes""fmt""hash/crc32")// String hashes a string to a unique hashcode.//// crc32 returns a uint32, but for our use we need// and non negative integer. Here we cast to an integer// and invert it if the result is negative. String(s string) int {v := int(crc32.ChecksumIEEE([]byte(s)))if v >= 0 {turn v}if -v >= 0 {rern -v}// v == MinIntreturn 0}trings hashes a list of strings to a unique hashcode. Strings(strings []string) string {var buf bytes.Bufferfor _, s := range strings {buf.iteString(fmt.Sprintf("%s-", s))}return fmt.Sprintf("%d", String(buf.String()))}